## Refactor plan

**Strategy:** promisify the leaf callback APIs, express the flow as an async function with `try/catch` mirroring each original error branch, and re-expose a callback-style `processOrder` via `util.callbackify`.

**Error-path mapping (preserved exactly):**
- `startTransaction` fails → bubble, no compensation (no tx yet).
- `reserve` fails → `rollback` then throw.
- `charge` fails → `release` → `rollback` → throw.
- `saveOrder` fails → `refund` → `release` → `rollback` → throw (sequential, matches original nesting).
- `commit` fails → throw, no compensation (original deliberately had none).
- `notifier.send` fails → `console.warn`, resolve with order (non-fatal).

**Compensation semantics:** `rollback`, `release`, `refund` ignore their own errors (original callbacks had no `err` check). Wrapped in promises that always resolve.

**Public API:** `callbackify(processOrderAsync)` produces a `(orderId, userId, items, callback)` function — signature identical to original.

## Resulting code

```javascript
// lib/order_processor.js
const { promisify, callbackify } = require('util');
const db = require('./db');
const payment = require('./payment');
const inventory = require('./inventory');
const notifier = require('./notifier');

const startTransaction = promisify(db.startTransaction);
const reserveInventory = promisify(inventory.reserve);
const chargePayment    = promisify(payment.charge);
const saveOrder        = promisify(db.saveOrder);
const sendNotification = promisify(notifier.send);

// Best-effort compensations: errors are swallowed to match original semantics.
const rollback = (tx) =>
  new Promise((resolve) => tx.rollback(() => resolve()));
const releaseInventory = (tx, reservationId) =>
  new Promise((resolve) => inventory.release(tx, reservationId, () => resolve()));
const refundPayment = (chargeId) =>
  new Promise((resolve) => payment.refund(chargeId, () => resolve()));
const commit = (tx) =>
  new Promise((resolve, reject) => tx.commit((err) => (err ? reject(err) : resolve())));

async function processOrderAsync(orderId, userId, items) {
  const tx = await startTransaction();

  let reservation;
  try {
    reservation = await reserveInventory(tx, items);
  } catch (err) {
    await rollback(tx);
    throw err;
  }

  let charge;
  try {
    charge = await chargePayment(userId, reservation.total);
  } catch (err) {
    await releaseInventory(tx, reservation.id);
    await rollback(tx);
    throw err;
  }

  let order;
  try {
    order = await saveOrder(tx, orderId, {
      userId,
      items,
      reservationId: reservation.id,
      chargeId: charge.id,
    });
  } catch (err) {
    await refundPayment(charge.id);
    await releaseInventory(tx, reservation.id);
    await rollback(tx);
    throw err;
  }

  await commit(tx); // original: commit failure bubbles with no compensation

  try {
    await sendNotification(userId, 'order_placed', order);
  } catch (notifyErr) {
    console.warn('notify failed:', notifyErr);
  }

  return order;
}

module.exports = { processOrder: callbackify(processOrderAsync) };
```

**Notes on equivalence:**
- `callbackify` invokes the callback on `process.nextTick`; original invokes from I/O callbacks (also async). No observable difference to test harnesses.
- Compensation order (refund → release → rollback) matches the original nested sequence.
- If a promisified dependency doesn't follow node-style `(err, result)` callbacks, swap `promisify(fn)` for a hand-written wrapper.
